// Slash Command Definition: /ban
client.slashCommands.set('ban', new SlashCommandBuilder()
 .setName('ban')
 .setDescription('Bans a member from the server.')
 .addUserOption(option =>
    option.setName('target')
     .setDescription('The user to ban')
     .setRequired(true))
 .addStringOption(option =>
    option.setName('reason')
     .setDescription('Reason for the ban (optional)')
     .setRequired(false))
 .setDefaultMemberPermissions(Permissions.FLAGS.BanMembers));

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const command = interaction.commandName;

  switch (command) {
    case 'ban':
      await handleBanCommand(interaction);
      break;
    default:
      console.error(`Unknown command: ${command}`);
  }
});

async function handleBanCommand(interaction) {
  const targetUser = interaction.options.getUser('target');
  const reason = interaction.options.getString('reason') || 'No reason provided';

  if (!interaction.member.permissions.has(Permissions.FLAGS.BanMembers)) {
    return interaction.reply({ content: 'You lack permission to ban users.', ephemeral: true });
  }

